// Replace these with your actual sensor variable names.
// They should be set upstream by your sensor input nodes
// (e.g. Modbus, MQTT, OPC-UA, or a previous function node).
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    T_outside: msg.sensors.T_outside,
    T_inside:  msg.sensors.T_inside,
    T_floor:   msg.sensors.T_floor,
    SR_direct: msg.sensors.SR_direct
};
return msg;

// msg.payload = { fan_on: 0|1, heater_on: 0|1, action: 0-3, source: 'mpc'|'ppo' }
var r = msg.payload;
node.warn('Action: fan=' + r.fan_on + ' heater=' + r.heater_on + ' (source: ' + r.source + ')');

// Send fan command on output 1, heater command on output 2
var fanMsg    = { payload: r.fan_on };
var heaterMsg = { payload: r.heater_on };
return [fanMsg, heaterMsg];

// Log the raw sensor readings + the action taken
var decision = msg.payload;
msg.headers = { 'Content-Type': 'application/json' };
msg.payload = {
    T_outside: msg.sensors.T_outside,
    T_inside:  msg.sensors.T_inside,
    T_floor:   msg.sensors.T_floor,
    SR_direct: msg.sensors.SR_direct,
    fan_on:    decision.fan_on,
    heater_on: decision.heater_on
};
return msg;
